// Regression: --budget / --per-agent-budget / --total-budget used to accept
// non-numeric input via parseFloat(), which returns NaN. Downstream cost-guard
// does `cost > opts.perAgentBudget`, and `cost > NaN` is false — so an
// unparseable budget silently disabled the safety flag. Same bug class as
// parseIntArg, same fix (parseFloatArg validates + exits 2).

const CLI = new URL("../src/cli.ts", import.meta.url).pathname;

async function runCli(...args: string[]): Promise<{ code: number; stderr: string }> {
  const cmd = new Deno.Command("deno", {
    args: ["run", "--allow-all", CLI, ...args],
    stdout: "piped",
    stderr: "piped",
  });
  const { code, stderr } = await cmd.output();
  return { code, stderr: new TextDecoder().decode(stderr) };
}

let pass = 0;
let fail = 0;
function check(cond: boolean, label: string): void {
  if (cond) { pass++; console.log(`  ✓ ${label}`); }
  else      { fail++; console.log(`  ✗ ${label}`); }
}

console.log("Float-arg validation (budget flags):");

// refine --per-agent-budget garbage → exit 2 (not 0, not NaN-silently-accepted)
{
  const r = await runCli("refine", ".", "--per-agent-budget", "abc", "--max", "1");
  check(r.code === 2, "refine --per-agent-budget abc exits 2");
  check(/Invalid value for --per-agent-budget/.test(r.stderr), "stderr names the offending flag");
  check(/"abc"/.test(r.stderr), "stderr echoes the bad value");
}

{
  const r = await runCli("refine", ".", "--total-budget", "not-a-number", "--max", "1");
  check(r.code === 2, "refine --total-budget not-a-number exits 2");
  check(/--total-budget/.test(r.stderr), "stderr names --total-budget");
}

// Negative budget is also rejected (min: 0).
{
  const r = await runCli("refine", ".", "--per-agent-budget", "-5", "--max", "1");
  check(r.code === 2, "refine --per-agent-budget -5 exits 2 (min=0)");
}

// workflow --budget garbage → exit 2
{
  const r = await runCli("workflow", "nonexistent.md", "--budget", "xyz");
  check(r.code === 2, "workflow --budget xyz exits 2");
  check(/--budget/.test(r.stderr), "workflow stderr names --budget");
}

// mxit --budget garbage → exit 2
{
  const r = await runCli("mxit", "nonexistent-tasks.md", "--budget", "NaN");
  check(r.code === 2, "mxit --budget NaN exits 2");
}

// Happy path: a valid float is still accepted (smoke check). We don't care
// whether the command ultimately succeeds — just that the parse itself
// doesn't kill it with exit 2.
{
  const r = await runCli("workflow", "nonexistent.md", "--budget", "3.5");
  check(r.code !== 2, "workflow --budget 3.5 passes parse (exit != 2)");
}

console.log(`\n${pass} passed, ${fail} failed`);
Deno.exit(fail === 0 ? 0 : 1);

