/**
 * Regression test: workflow sandbox preset error lists available presets.
 *
 * Previously `runWorkflow` threw "Unknown sandbox preset: foo" with no hint
 * about valid choices — a user seeing the message had to read source to act.
 * The message now enumerates the available preset names inline so the error
 * is self-describing at the trust boundary (workflow spec / CLI override).
 *
 * Run:  deno run --allow-all tests/test-workflow-sandbox-error.ts
 */

import { runWorkflow } from "../src/workflow.ts";
import { SANDBOX_PRESETS } from "../src/spawner.ts";

let passed = 0;
let failed = 0;

function check(name: string, predicate: boolean, detail?: string): void {
  if (predicate) {
    console.log(`  \x1b[32m✓\x1b[0m ${name}`);
    passed++;
  } else {
    console.log(`  \x1b[31m✗\x1b[0m ${name}${detail ? ` — ${detail}` : ""}`);
    failed++;
  }
}

const tmpDir = await Deno.makeTempDir({ prefix: "expo-workflow-sandbox-err-" });
const wfPath = `${tmpDir}/wf.md`;
await Deno.writeTextFile(
  wfPath,
  [
    "# T",
    "## agents",
    "### a1",
    "do nothing",
    "## sandbox",
    "permissive",
    "## synthesize",
    "ignore",
    "",
  ].join("\n"),
);

console.log("\n=== unknown sandbox preset error ===");
let err: unknown;
try {
  await runWorkflow({
    workflowPath: wfPath,
    sandboxOverride: "not-a-real-preset",
    dryRun: true,
  });
} catch (e) {
  err = e;
}

const msg = err instanceof Error ? err.message : String(err);
check("throws an Error", err instanceof Error, `got ${typeof err}`);
check("message names the bad preset", msg.includes("not-a-real-preset"), msg);
check("message lists available presets", msg.toLowerCase().includes("available"), msg);

const presetNames = Object.keys(SANDBOX_PRESETS);
check(
  "message includes every known preset",
  presetNames.every((p) => msg.includes(p)),
  `missing presets; msg=${msg}`,
);

await Deno.remove(tmpDir, { recursive: true });

console.log(`\n${passed} passed, ${failed} failed`);
if (failed > 0) Deno.exit(1);

